func accountingMatchesDisk(root string, items []f5.AccountItem) bool {
        for _, item := range items {
                path := filepath.Join(root, item.Path)
                st, err := os.Stat(path)
                if err != nil {
                        return false
                }
                if !st.Mode().IsRegular() {
                        return false
                }
                if int(st.Size()) != item.Bytes {
                        return false
                }
